import React from 'react';
import { Link } from 'react-router-dom';
import { FaEye } from 'react-icons/fa';
import moment from 'moment';

export default function VideoCard({ video }) {
    return (
        <Link to={`/video/${video.id}`} className="block group">
            <div className="figma-card">
                <div className="figma-thumbnail">
                    {video.thumbnail ? (
                        <img src={video.thumbnail} alt={video.title} />
                    ) : (
                        <div className="absolute inset-0 bg-gradient-to-br from-purple-900 to-pink-900 flex items-center justify-center">
                            <span className="text-4xl">🎬</span>
                        </div>
                    )}
                </div>
                <div className="figma-info">
                    <h3 className="figma-title group-hover:text-purple-400 transition">
                        {video.title}
                    </h3>
                    <div className="figma-author">
                        <div className="figma-author-avatar">
                            {video.author?.username?.[0]?.toUpperCase()}
                        </div>
                        <span className="figma-author-name group-hover:text-purple-400 transition">
                            {video.author?.username}
                        </span>
                    </div>
                    <div className="figma-stats">
                        <span className="flex items-center gap-1"><FaEye /> {video.views?.toLocaleString()}</span>
                        <span>{moment(video.created_at).fromNow()}</span>
                    </div>
                </div>
            </div>
        </Link>
    );
}
